def route_request(config, responses):
    surface = config['serving_surface']
    budget = config['retry_budget']
    max_attempts = budget + 1
    attempts = 0
    for reply in responses:
        if attempts >= max_attempts:
            break
        attempts += 1
        if reply == 'ok':
            return {'outcome': 'success', 'attempts': attempts, 'surface': surface}
    return {'outcome': 'failed', 'attempts': attempts, 'surface': surface}

def route_request(config, responses):
    surface = config['serving_surface']
    allowed = responses[: config['retry_budget'] + 1]
    for i, reply in enumerate(allowed, start=1):
        if reply == 'ok':
            return {'outcome': 'success', 'attempts': i, 'surface': surface}
    return {'outcome': 'failed', 'attempts': len(allowed), 'surface': surface}
